export interface Exercise {
  title: string;
  desc: string;
  hint: string;
  expected: string;
  ctx?: string;
  dataset_override?: string;
  final?: boolean;
}

export interface CareerLevel {
  level: number;
  name: string;
  dataset: string;
  exercises: Exercise[];
}
